const item = $input.first() ?? { json: {}, binary: {} };

function getNodeItemsSafe(nodeName) {
  if (typeof $items !== 'function') return [];
  try {
    return $items(nodeName) || [];
  } catch (error) {
    const message = String(error?.message ?? error ?? '');
    if (message.includes("hasn't been executed") || message.includes('not executed')) {
      return [];
    }
    return [];
  }
}

const hvItems = getNodeItemsSafe('REQ - Human Validation');
const hv1Items = getNodeItemsSafe('REQ - Human Validation1');
const loopItems = getNodeItemsSafe('REQ - Loop Decision');

const hvJson = hvItems[0]?.json ?? {};
const hv1Json = hv1Items[0]?.json ?? {};
const loopJson = loopItems[0]?.json ?? {};

const hvBinary = hvItems[0]?.binary ?? {};
const hv1Binary = hv1Items[0]?.binary ?? {};
const loopBinary = loopItems[0]?.binary ?? {};

const mergedJson = { ...hvJson, ...hv1Json, ...loopJson, ...(item.json ?? {}) };
const mergedBinary = { ...hvBinary, ...hv1Binary, ...loopBinary, ...(item.binary ?? {}) };

const requirements = String(mergedJson.requirements ?? '').trim();
if (!requirements) {
  throw new Error('Requirements Markdown draft is missing for refinement generation.');
}

const reviewerFeedback = [
  mergedJson.feedback,
  mergedJson.Feedback,
  loopJson.feedback,
  loopJson.Feedback,
  hv1Json.feedback,
  hv1Json.Feedback,
  hvJson.feedback,
  hvJson.Feedback,
]
  .map((value) => String(value ?? '').trim())
  .find((value) => value.length > 0) || 'Reviewer requested changes without additional details.';

const revisionNumber = Math.max(0, Math.trunc(Number(mergedJson.revisionNumber ?? 0) || 0)) + 1;

function splitLines(text) {
  return String(text ?? '').replace(/\r\n/g, '\n').split('\n');
}

function looksTextLike(binaryEntry, key) {
  const mime = String(binaryEntry?.mimeType ?? '').toLowerCase();
  const extRaw = String(binaryEntry?.fileExtension ?? '').toLowerCase();
  const ext = extRaw.startsWith('.') ? extRaw.slice(1) : extRaw;

  const textExt = new Set([
    'txt', 'md', 'markdown', 'json', 'yaml', 'yml', 'csv', 'tsv', 'xml', 'html', 'htm',
    'js', 'ts', 'py', 'java', 'c', 'cpp', 'cs', 'sql', 'log', 'ini', 'cfg',
  ]);

  if (mime.startsWith('text/')) return true;
  if (mime.includes('json') || mime.includes('xml') || mime.includes('yaml')) return true;
  if (textExt.has(ext)) return true;

  const keyLower = String(key ?? '').toLowerCase();
  if (keyLower.endsWith('.txt') || keyLower.endsWith('.md') || keyLower.endsWith('.json')) return true;

  return false;
}

function decodeText(binaryEntry) {
  try {
    const raw = String(binaryEntry?.data ?? '');
    if (!raw) return '';
    return Buffer.from(raw, 'base64').toString('utf8');
  } catch (error) {
    return '';
  }
}

const attachmentEntries = Object.entries(mergedBinary)
  .filter(([key]) => /^attachments?(?:_|$)/i.test(String(key)));

const attachmentSummaries = [];
const attachmentTextBlocks = [];

let totalTextChars = 0;
const maxTotalChars = 24000;
const maxPerFileChars = 6000;

for (const [key, bin] of attachmentEntries) {
  const fileName = String(bin?.fileName ?? key);
  const mimeType = String(bin?.mimeType ?? 'application/octet-stream');
  const fileSize = Number(bin?.fileSize ?? 0);

  attachmentSummaries.push({
    key,
    fileName,
    mimeType,
    fileSize,
  });

  if (!looksTextLike(bin, key)) continue;
  if (totalTextChars >= maxTotalChars) continue;

  const text = decodeText(bin).trim();
  if (!text) continue;

  const remaining = maxTotalChars - totalTextChars;
  const take = Math.min(maxPerFileChars, remaining);
  const excerpt = text.slice(0, take);

  attachmentTextBlocks.push(
    `Attachment: ${fileName} (${mimeType})\n---\n${excerpt}`,
  );

  totalTextChars += excerpt.length;
}

const numberedMarkdown = splitLines(requirements)
  .map((line, index) => `${index + 1}: ${line}`)
  .join('\n');

const attachmentSummaryText = attachmentSummaries.length
  ? attachmentSummaries
    .map((a, i) => `${i + 1}) ${a.fileName} | mime=${a.mimeType} | size=${a.fileSize}`)
    .join('\n')
  : '[No attachments provided.]';

const attachmentExtractedText = attachmentTextBlocks.length
  ? attachmentTextBlocks.join('\n\n')
  : '[No text could be extracted from attachments automatically.]';

const patchPrompt = [
  'Reviewer feedback:',
  reviewerFeedback,
  '',
  'Attachment metadata:',
  attachmentSummaryText,
  '',
  'Extracted attachment text (partial when available):',
  attachmentExtractedText,
  '',
  'Current markdown draft with line numbers:',
  numberedMarkdown,
].join('\n');

return [{
  json: {
    requirements,
    reviewerFeedback,
    revisionNumber,
    attachmentCount: attachmentSummaries.length,
    attachmentSummaries,
    patchPrompt,
  },
  ...(mergedBinary && Object.keys(mergedBinary).length > 0 ? { binary: mergedBinary } : {}),
}];

function joinContentBlocks(value) {
  if (!Array.isArray(value)) return "";
  const parts = value
    .map((entry) => {
      if (typeof entry === "string") return entry;
      if (entry && typeof entry.text === "string") return entry.text;
      if (entry && typeof entry.content === "string") return entry.content;
      return "";
    })
    .filter((entry) => entry && entry.trim());
  return parts.join("\n").trim();
}

function toTokenCount(value) {
  const parsed = Number(value);
  if (!Number.isFinite(parsed) || parsed < 0) return null;
  return Math.trunc(parsed);
}

function extractUsageTokensObject(obj) {
  if (!obj || typeof obj !== "object") return null;

  const candidates = [
    obj.usage?.completion_tokens,
    obj.usage?.output_tokens,
    obj.usage?.completionTokens,
    obj.usage?.outputTokens,
    obj.completion_tokens,
    obj.output_tokens,
    obj.data?.usage?.completion_tokens,
    obj.data?.usage?.output_tokens,
    obj.choices?.[0]?.usage?.completion_tokens,
    obj.choices?.[0]?.usage?.output_tokens,
  ];

  for (const candidate of candidates) {
    const count = toTokenCount(candidate);
    if (count !== null) return count;
  }

  return null;
}

function extractUsageTokensFromSseText(value) {
  if (typeof value !== "string") return null;
  const text = value.trim();
  if (!text || !text.includes("data:")) return null;

  let lastCount = null;
  const lines = text.split(/\r?\n/);

  for (const rawLine of lines) {
    const line = rawLine.trim();
    if (!line.startsWith("data:")) continue;

    const payload = line.slice(5).trim();
    if (!payload || payload === "[DONE]") continue;

    try {
      const chunk = JSON.parse(payload);
      const count = extractUsageTokensObject(chunk);
      if (count !== null) lastCount = count;
    } catch {
      // Ignore malformed chunks
    }
  }

  return lastCount;
}

function normalizeStreamingText(value) {
  if (typeof value !== "string") return "";
  const text = value.trim();
  if (!text) return "";

  if (!text.includes("data:")) return text;

  const collected = [];
  const lines = text.split(/\r?\n/);

  for (const rawLine of lines) {
    const line = rawLine.trim();
    if (!line.startsWith("data:")) continue;

    const payload = line.slice(5).trim();
    if (!payload || payload === "[DONE]") continue;

    try {
      const chunk = JSON.parse(payload);
      const delta = chunk?.choices?.[0]?.delta?.content;
      const messageContent = chunk?.choices?.[0]?.message?.content;
      const plainText = chunk?.choices?.[0]?.text;

      if (typeof delta === "string") collected.push(delta);
      else if (typeof messageContent === "string") collected.push(messageContent);
      else if (typeof plainText === "string") collected.push(plainText);
    } catch {
      // Ignore malformed chunks and keep parsing
    }
  }

  const merged = collected.join("").trim();
  return merged || text;
}

function firstText(...values) {
  for (const value of values) {
    if (typeof value === "string" && value.trim()) {
      const normalized = normalizeStreamingText(value);
      if (normalized && normalized.trim()) return normalized.trim();
    }

    const joined = joinContentBlocks(value);
    if (joined) {
      const normalized = normalizeStreamingText(joined);
      if (normalized && normalized.trim()) return normalized.trim();
    }
  }
  return "";
}

function parseMaybeJson(value) {
  if (typeof value !== "string") return null;
  const trimmed = value.trim();
  if (!trimmed.startsWith("{") && !trimmed.startsWith("[")) return null;
  try {
    return JSON.parse(trimmed);
  } catch {
    return null;
  }
}

function tryParseJsonObject(text) {
  if (typeof text !== "string") return null;
  const start = text.indexOf("{");
  const end = text.lastIndexOf("}");
  if (start === -1 || end <= start) return null;
  const candidate = text.slice(start, end + 1);
  try {
    return JSON.parse(candidate);
  } catch {
    return null;
  }
}

function extractModelText(json) {
  if (!json || typeof json !== "object") return "";

  const direct = firstText(
    json.text,
    json.response,
    json.output,
    json.result,
    json.answer,
    json.completion,
    json.generated_text,
    json.message?.content,
    json.choices?.[0]?.message?.content,
    json.choices?.[0]?.text,
    json.data?.text,
    json.data?.response,
    json.data?.output,
    json.data?.result,
    json.data?.choices?.[0]?.message?.content,
    json.data?.choices?.[0]?.text,
    json.content,
    json.data?.content,
    json.data
  );
  if (direct) return direct;

  const parsedFromStrings = [json.response, json.text, json.output, json.result, json.data]
    .map((value) => parseMaybeJson(value))
    .filter((value) => value && typeof value === "object");

  for (const parsed of parsedFromStrings) {
    const parsedText = extractModelText(parsed);
    if (parsedText) return parsedText;
  }

  return "";
}

function extractOutputTokens(json, rawModelText) {
  const direct = extractUsageTokensObject(json);
  if (direct !== null) {
    return { outputTokens: direct, outputTokensSource: "usage.completion_tokens" };
  }

  const maybeSse = [json.data, json.response, json.output, json.result, json.text];
  for (const value of maybeSse) {
    const fromSse = extractUsageTokensFromSseText(value);
    if (fromSse !== null) {
      return { outputTokens: fromSse, outputTokensSource: "stream.usage.completion_tokens" };
    }
  }

  const estimated = Math.max(1, Math.round(String(rawModelText ?? "").length / 4));
  return { outputTokens: estimated, outputTokensSource: "estimated_char_div4" };
}

function decodeQuoted(value) {
  const trimmed = String(value ?? "").trim();
  if (!trimmed) return "";

  if (trimmed.startsWith("\"") && trimmed.endsWith("\"")) {
    try {
      return JSON.parse(trimmed);
    } catch {
      return trimmed
        .slice(1, -1)
        .replace(/\\r\\n/g, "\n")
        .replace(/\\n/g, "\n")
        .replace(/\\t/g, "\t")
        .replace(/\\\"/g, "\"")
        .replace(/\\'/g, "'")
        .replace(/\\\\/g, "\\");
    }
  }

  if (trimmed.startsWith("'") && trimmed.endsWith("'")) {
    return trimmed
      .slice(1, -1)
      .replace(/\\r\\n/g, "\n")
      .replace(/\\n/g, "\n")
      .replace(/\\t/g, "\t")
      .replace(/\\\"/g, "\"")
      .replace(/\\'/g, "'")
      .replace(/\\\\/g, "\\");
  }

  return trimmed;
}

function normalizeCandidate(text) {
  let out = String(text ?? "").trim();
  if (!out) return "";

  const fenced = out.match(/^\`\`\`(?:markdown|md|txt)?\s*([\s\S]*?)\`\`\`$/i);
  if (fenced) out = fenced[1].trim();

  out = out
    .replace(/^\s*["']?requirements["']?\s*:\s*/i, "")
    .replace(/^\s*["']?response["']?\s*:\s*/i, "")
    .trim();

  out = decodeQuoted(out);

  if (!out.includes("\n") && /\\n|\\r|\\t/.test(out)) {
    out = out
      .replace(/\\r\\n/g, "\n")
      .replace(/\\n/g, "\n")
      .replace(/\\r/g, "\n")
      .replace(/\\t/g, "\t")
      .replace(/\\\"/g, "\"")
      .replace(/\\'/g, "'")
      .replace(/\\\\/g, "\\");
  }

  out = out.replace(/\r\n/g, "\n").replace(/\r/g, "\n").trim();

  const firstHeadingIndex = out.search(/(^|\n)#{1,6}\s+\S/);
  if (firstHeadingIndex > 0) {
    const prefix = out.slice(0, firstHeadingIndex).toLowerCase();
    if (
      prefix.includes("here") ||
      prefix.includes("generated") ||
      prefix.includes("requirements") ||
      prefix.includes("specification")
    ) {
      out = out.slice(firstHeadingIndex).trim();
    }
  }

  const trailingMarkers = [
    /\n(?:Notes?|Explanation|Rationale|Summary)\s*:/i,
    /\n(?:If you'd like|If you want|Let me know|I can help)/i,
    /\nThis (?:requirements|document|specification) /i,
  ];
  let endIndex = out.length;
  for (const marker of trailingMarkers) {
    const match = marker.exec(out);
    if (match && match.index > 0) endIndex = Math.min(endIndex, match.index);
  }
  out = out.slice(0, endIndex).trim();

  return out;
}

function collectRequirementsCandidatesFromObject(obj, candidates) {
  if (!obj || typeof obj !== "object") return;

  const valueCandidates = [
    obj.requirements,
    obj.output?.requirements,
    obj.data?.requirements,
    obj.result?.requirements,
    obj.response?.requirements,
    obj.message?.requirements,
    obj.content?.requirements,
    obj.markdown,
    obj.data?.markdown,
  ];

  for (const value of valueCandidates) {
    if (typeof value === "string" && value.trim()) candidates.push(value);
  }

  if (Array.isArray(obj)) {
    for (const entry of obj) collectRequirementsCandidatesFromObject(entry, candidates);
    return;
  }

  for (const [key, value] of Object.entries(obj)) {
    if (!value || typeof value !== "object" || key === "usage") continue;
    collectRequirementsCandidatesFromObject(value, candidates);
  }
}

function scoreCandidate(text) {
  let score = text.length;
  if (/^#\s+/.test(text)) score += 1200;
  if (/\n##\s+/.test(text)) score += 800;
  if (/\bMUST\b/.test(text)) score += 400;
  if (/\b(REQ|DATA|SEC|TST)-\d{3}\b/.test(text)) score += 500;
  if (/^\s*\{\s*"/.test(text)) score -= 2000;
  if (/^\s*\[/.test(text)) score -= 1500;
  return score;
}

function extractRequirementsMarkdown(rawText) {
  if (typeof rawText !== "string" || !rawText.trim()) {
    throw new Error("Requirements response is empty.");
  }

  const raw = rawText.trim();
  const candidates = [raw];

  const fencedMatches = [...raw.matchAll(/\`\`\`(?:markdown|md|txt)?\s*([\s\S]*?)\`\`\`/gi)];
  for (const match of fencedMatches) {
    if (match && typeof match[1] === "string") candidates.push(match[1]);
  }

  const parsedWhole = parseMaybeJson(raw);
  if (parsedWhole && typeof parsedWhole === "object") {
    collectRequirementsCandidatesFromObject(parsedWhole, candidates);
  }

  const parsedEmbedded = tryParseJsonObject(raw);
  if (parsedEmbedded && typeof parsedEmbedded === "object") {
    collectRequirementsCandidatesFromObject(parsedEmbedded, candidates);
  }

  const labelled = raw.match(/(?:^|\n)\s*["']?requirements["']?\s*:\s*([\s\S]*)/i);
  if (labelled) candidates.push(labelled[1]);

  const firstHeadingIndex = raw.search(/(^|\n)#{1,6}\s+\S/);
  if (firstHeadingIndex >= 0) candidates.push(raw.slice(firstHeadingIndex));

  const normalized = candidates.map(normalizeCandidate).filter((value) => value.length > 0);
  if (!normalized.length) {
    throw new Error("Could not extract requirements content from model output.");
  }

  let best = normalized[0];
  let bestScore = scoreCandidate(best);
  for (const candidate of normalized.slice(1)) {
    const score = scoreCandidate(candidate);
    if (score > bestScore) {
      best = candidate;
      bestScore = score;
    }
  }

  return best;
}

const item = $input.first() ?? { json: {}, binary: {} };
const json = item.json ?? {};
const rawModelText = extractModelText(json);
const tokenInfo = extractOutputTokens(json, rawModelText);

return [{
  json: {
    response: extractRequirementsMarkdown(rawModelText),
    revisionNumber: Number(json.revisionNumber ?? 0) || 0,
    outputTokens: tokenInfo.outputTokens,
    outputTokensSource: tokenInfo.outputTokensSource,
  },
  ...(item.binary && Object.keys(item.binary).length > 0 ? { binary: item.binary } : {}),
}];

