function normalizeText(value) {
  return String(value ?? '')
    .replace(/\u0000/g, '')
    .replace(/\u00A0/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/[\u200B-\u200D\uFEFF]/g, '')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{4,}/g, '\n\n\n')
    .split('\n')
    .map((line) => line.replace(/\s+$/g, ''))
    .join('\n')
    .trim();
}

function fixCommonLigatures(value) {
  return String(value ?? '')
    .replace(/ï¬/g, 'fi')
    .replace(/ï¬‚/g, 'fl')
    .replace(/ï¬€/g, 'ff')
    .replace(/ï¬ƒ/g, 'ffi')
    .replace(/ï¬„/g, 'ffl')
    .replace(/ï¬…/g, 'ft')
    .replace(/ï¬†/g, 'st');
}

function scoreCandidate(source, text) {
  const lengthScore = text.length;
  const sourceBoosts = {
    text: 90000,
    extractedText: 80000,
    markdown: 75000,
    pdfText: 70000,
    pages_joined: 70000,
    data_text: 65000,
    content: 60000,
    fallback_field: 40000,
  };
  return (sourceBoosts[source] ?? 10000) + lengthScore;
}

function extractTextFromItem(json) {
  if (!json || typeof json !== 'object') return '';
  const candidates = [];
  const push = (source, value) => {
    if (typeof value !== 'string') return;
    const normalized = normalizeText(fixCommonLigatures(value));
    if (!normalized) return;
