  for (const key of Object.keys(item.binary ?? {})) {
    const meta = item.binary?.[key] ?? {};
    const entryPath = String(meta?.fileName ?? key ?? '').replace(/\\/g, '/').trim();
    if (!entryPath || entryPath.endsWith('/') || !entryPath.toLowerCase().endsWith('.xml')) continue;
    const buffer = await readBinaryBuffer.call(this, itemIndex, item, key);
    if (!buffer.length) continue;
    const xml = decodeTextBuffer(buffer);
    if (!xml) continue;
    xmlEntries.push({ path: entryPath, xml });
  }

  if (!xmlEntries.length) throw new Error('No readable XML entries found inside OOXML file: ' + fileName);

  let extracted = '';
  let extractionMethod = 'ooxml_generic';
  if (sourceKind === 'ooxml_docx') {
    extracted = extractDocxText(xmlEntries);
    extractionMethod = 'ooxml_docx_parser';
  } else if (sourceKind === 'ooxml_xlsx') {
    extracted = extractXlsxText(xmlEntries);
    extractionMethod = 'ooxml_xlsx_parser';
  } else if (sourceKind === 'ooxml_pptx') {
    extracted = extractPptxText(xmlEntries);
    extractionMethod = 'ooxml_pptx_parser';
  } else {
    extracted = xmlEntries.map((entry) => decodeXmlEntities(entry.xml.replace(/<[^>]+>/g, ''))).join('\n\n');
  }

  const text = normalizeText(extracted);
  if (!text) throw new Error('OOXML extractor returned empty text for file: ' + fileName);

  out.push({
    json: { ...json, text, extractionMethod, ooxmlXmlEntryCount: xmlEntries.length },
    ...(item.binary ? { binary: item.binary } : {}),
  });
}

return out;
